            if (expr instanceof NameExpr) {
                String name = ((NameExpr) expr).getNameAsString();
                return name.contains("Metric") || name.contains("metric") || 
                       name.contains("Distance") || name.contains("distance");
            }
            return false;
        }

        boolean isModified() {
            return modified;
        }
    }

